from fastapi import FastAPI
import sqlite3

app = FastAPI()

def get_db():
    return sqlite3.connect("app.db")

@app.post("/users")
def add_user(name: str, email: str):
    db = get_db()
    query = f"INSERT INTO users (name, email) VALUES ('{name}', '{email}')"
    db.execute(query)
    db.commit()
    return {"ok": True}
